import{_ as o,o as e,c as r,a2 as d}from"./chunks/framework.ChW7XBuO.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Rolebox","text":"AI Agent 编排框架","tagline":"声明式 YAML · 并行 dispatch · 持久记忆 — 秒级部署你的 AI 工程团队","image":{"src":"/logo.svg","alt":"Rolebox"},"actions":[{"theme":"brand","text":"快速开始","link":"/01-Overview/quick-start"},{"theme":"alt","text":"GitHub","link":"https://github.com/EricMoin/rolebox"},{"theme":"alt","text":"角色注册表","link":"https://github.com/EricMoin/oh-my-role"}]},"features":[{"icon":"🧩","title":"角色驱动架构","details":"通过 role.yaml 声明式定义 AI 代理的能力、权限与交互方式"},{"icon":"⚡","title":"灵活调度系统","details":"支持同步 / 异步 dispatch、深度嵌套子任务、后台执行与预算控制"},{"icon":"🔗","title":"多代理协作","details":"基于协作图与领域路由的代理间通信与编排"},{"icon":"🛠️","title":"技能与函数系统","details":"可插拔技能加载、函数依赖注入与 State Machine 生命周期管理"},{"icon":"🧠","title":"持久记忆系统","details":"SQLite + FTS5 全文搜索，跨会话自动注入，workspace/role 隔离，`|memory|` 模式一键记忆"},{"icon":"📬","title":"桌面通知","details":"原生 OS 通知，空闲检测免打扰，静音时段配置，事件过滤与突发抑制"},{"icon":"🔄","title":"资产热重载","details":"编辑 role.yaml 或技能文件后即时生效，无需重启 — 开发与调试零等待"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),a={name:"index.md"};function s(i,t,l,n,c,h){return e(),r("div",null,[...t[0]||(t[0]=[d('<h2 id="🚀-5-分钟构建第一个多代理团队" tabindex="-1">🚀 5 分钟构建第一个多代理团队 <a class="header-anchor" href="#🚀-5-分钟构建第一个多代理团队" aria-label="Permalink to &quot;🚀 5 分钟构建第一个多代理团队&quot;">​</a></h2><p>从零到拥有一个带 Emperor 编排器的多代理团队，只需三步：</p><div class="tip custom-block"><p class="custom-block-title">📦 步骤一：安装 rolebox</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rolebox</span></span></code></pre></div><p>然后在 <code>opencode.jsonc</code> 中添加 <code>&quot;plugin&quot;: [&quot;rolebox&quot;]</code>。</p></div><div class="tip custom-block"><p class="custom-block-title">🔧 步骤二：初始化第一个角色</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rolebox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>这会创建一个完整的角色目录，包含 <code>role.yaml</code> 配置和技能入口。</p></div><div class="tip custom-block"><p class="custom-block-title">🚀 步骤三：安装 Emperor 编排器</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rolebox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> emperor</span></span></code></pre></div><p>安装完成后重启 opencode，你就拥有了一个计划→调度→验证→修订闭环的 AI 工程主管团队。</p></div><p>了解更多 → <a href="/rolebox-docs/01-Overview/quick-start.html">快速开始指南</a></p><h2 id="rolebox-能为你做什么" tabindex="-1">rolebox 能为你做什么 <a class="header-anchor" href="#rolebox-能为你做什么" aria-label="Permalink to &quot;rolebox 能为你做什么&quot;">​</a></h2><p>每次 AI 编程会话都从头开始。你的助手不记得昨天的架构决策、上周的 bug 修复、三个会话前你定下的编码规范。你需要重复解释，它重复犯错，进展变慢。</p><p><strong>rolebox 给你的 AI 装上持久记忆</strong> — 跨会话、跨项目，代理们记得一切。</p><p>但记忆只是起点。rolebox 把一个通用的聊天助手变成一支精密的工程团队：用 YAML 定义，秒级部署，永不遗忘。</p><h3 id="🧠-持久记忆系统" tabindex="-1">🧠 持久记忆系统 <a class="header-anchor" href="#🧠-持久记忆系统" aria-label="Permalink to &quot;🧠 持久记忆系统&quot;">​</a></h3><ul><li><strong>SQLite + FTS5</strong> — 对每一条存储的决策、规范和教训执行全文搜索</li><li><strong>Workspace vs Role 隔离</strong> — 项目知识全局共享，角色笔记私有保留</li><li><strong><code>|memory|</code> 模式</strong> — 回顾过往会话，提取持久知识，去重，持久化</li><li><strong>自动注入</strong> — 会话启动时相关记忆自动浮现为 <code>&lt;available_memory&gt;</code></li><li><strong>CLI</strong> — <code>rolebox memory list</code>、<code>search</code>、<code>export</code>、<code>stats</code></li></ul><h3 id="✂️-hashline-编辑-—-永不漂移的编辑" tabindex="-1">✂️ Hashline 编辑 — 永不漂移的编辑 <a class="header-anchor" href="#✂️-hashline-编辑-—-永不漂移的编辑" aria-label="Permalink to &quot;✂️ Hashline 编辑 — 永不漂移的编辑&quot;">​</a></h3><p>基于行号的编辑在文件变更时断裂。rolebox 使用<strong>内容哈希锚定编辑</strong>：</p><ul><li>每行标记内容哈希 — <code>LINE#HASH</code></li><li>编辑按哈希匹配，而非行号。文件在读和写之间发生变化时，编辑定位的是<em>内容</em>，而非行号</li><li><strong>多编辑批处理</strong>支持快照语义 — 所有编辑引用文件原始状态，自底向上应用，行号始终正确</li><li><strong>SHA-256 版本追踪</strong> — 在写入前检测外部修改</li></ul><h3 id="🔬-lsp-集成-30-工具" tabindex="-1">🔬 LSP 集成（30+ 工具） <a class="header-anchor" href="#🔬-lsp-集成-30-工具" aria-label="Permalink to &quot;🔬 LSP 集成（30+ 工具）&quot;">​</a></h3><p>你的 IDE 拥有的每个语言服务器工具，现在你的 AI 助手也能用。导航（go-to-definition、find-references）、诊断、代码操作、补全、格式化、悬停信息、符号搜索、调用层次结构 — 一个系统对接所有 LSP 服务器，自动检测。</p><h3 id="🚀-调度系统" tabindex="-1">🚀 调度系统 <a class="header-anchor" href="#🚀-调度系统" aria-label="Permalink to &quot;🚀 调度系统&quot;">​</a></h3><p>并行运行多个代理，追踪一切。后台执行配合真实并发控制（模型池信号量）、预算追踪、带完整上下文的任务重试、任务依赖图可视化、时间分桶活动视图、实时指标与观测。</p><div class="tip custom-block"><p class="custom-block-title">rolebox 的核心设计理念</p><ul><li><strong>YAML 优先</strong> — 无需编码，用声明式 YAML 定义角色、技能、子代理和协作关系</li><li><strong>容错设计</strong> — 即使 YAML 配置有误、技能缺失或函数引用断裂，rolebox 也会优雅降级而非崩溃</li><li><strong>渐进式采纳</strong> — 可从单个记忆插件起步，逐步扩展到完整的多代理编排团队</li></ul></div><hr><h2 id="rolebox-为-opencode-带来的能力" tabindex="-1">rolebox 为 opencode 带来的能力 <a class="header-anchor" href="#rolebox-为-opencode-带来的能力" aria-label="Permalink to &quot;rolebox 为 opencode 带来的能力&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>原生 opencode</th><th>+ rolebox</th></tr></thead><tbody><tr><td><strong>持久记忆</strong></td><td>❌ 会话从零开始</td><td>✅ SQLite + FTS5，自动注入过往决策</td></tr><tr><td><strong>多代理团队</strong></td><td>❌ 单一代理</td><td>✅ YAML 定义的专家团队，并行调度</td></tr><tr><td><strong>LSP 集成</strong></td><td>❌ 无语言服务器访问</td><td>✅ 30+ 工具（跳转定义、引用、重命名、诊断…）</td></tr><tr><td><strong>Hashline 编辑</strong></td><td>❌ 基于行号</td><td>✅ 内容哈希锚定 — 编辑永不漂移</td></tr><tr><td><strong>桌面通知</strong></td><td>❌ 无</td><td>✅ 原生 OS 通知、静音时段、空闲检测、节流</td></tr><tr><td><strong>会话分析</strong></td><td>❌ 基础会话列表</td><td>✅ 10 种工具：搜索、导出、分叉、对比、检查</td></tr><tr><td><strong>后台调度</strong></td><td>❌ 串行</td><td>✅ 真实并发，预算追踪</td></tr><tr><td><strong>任务依赖图</strong></td><td>❌ 扁平</td><td>✅ 可视化父子调度树</td></tr><tr><td><strong>函数状态机</strong></td><td>❌ 静态提示词</td><td>✅ 带证据与状态转换的生命周期管理</td></tr><tr><td><strong>上下文组装</strong></td><td>❌ 手动</td><td>✅ 跨域搜索（记忆 + 资产 + 任务 + 会话）</td></tr><tr><td><strong>热重载资产</strong></td><td>❌ 需重启</td><td>✅ 编辑 YAML，即时重载</td></tr><tr><td><strong>资产验证</strong></td><td>❌ 无</td><td>✅ 依赖与完整性检查</td></tr><tr><td><strong>可共享角色注册表</strong></td><td>❌ 无</td><td>✅ npm 风格 <code>rolebox install &lt;name&gt;</code></td></tr><tr><td><strong>编排器（Emperor）</strong></td><td>❌ 无</td><td>✅ 计划 → 调度 → 验证 → 修订闭环</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">📊 项目统计</p><p>rolebox 目前拥有：</p><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>说明</th></tr></thead><tbody><tr><td><strong>文档页面</strong></td><td>43 页</td><td>涵盖架构、指南、参考与高级主题</td></tr><tr><td><strong>内置工具</strong></td><td>80+</td><td>LSP、会话、记忆、调度、资产、网络等 10 大领域</td></tr><tr><td><strong>CLI 命令</strong></td><td>14 个</td><td>init、install、list、memory、checkpoint 等完整工具链</td></tr><tr><td><strong>恢复策略</strong></td><td>7 个</td><td>retry、compact、fallback-model、abort、remind-and-retry、truncate、summarize</td></tr><tr><td><strong>文档覆盖</strong></td><td>100%</td><td>每个 CLI 命令和配置项均有对应文档页面</td></tr></tbody></table></div><h2 id="📦-精选角色库" tabindex="-1">📦 精选角色库 <a class="header-anchor" href="#📦-精选角色库" aria-label="Permalink to &quot;📦 精选角色库&quot;">​</a></h2><p>rolebox 社区提供了丰富的预制角色，即装即用：</p><table tabindex="0"><thead><tr><th>角色</th><th>功能简介</th><th>安装命令</th></tr></thead><tbody><tr><td><strong>emperor</strong></td><td>顶层编排器 — 计划、调度、验证复杂工作至专业团队</td><td><code>rolebox install emperor</code></td></tr><tr><td><strong>software-architect</strong></td><td>系统设计与架构评审 — ADR、C4 模型、权衡分析</td><td><code>rolebox install software-architect</code></td></tr><tr><td><strong>react-frontend</strong></td><td>React/Next.js 前端开发 — 组件设计、状态管理</td><td><code>rolebox install react-frontend</code></td></tr><tr><td><strong>ai-designer</strong></td><td>AI 应用设计 — 人性化 UX、交互建模、设计系统</td><td><code>rolebox install ai-designer</code></td></tr><tr><td><strong>tauri</strong></td><td>桌面应用开发 — Tauri v2 IPC、插件、窗口管理</td><td><code>rolebox install tauri</code></td></tr><tr><td><strong>dart-flutter</strong></td><td>跨平台 Flutter 开发 — 完整 Gate 审查流水线</td><td><code>rolebox install dart-flutter</code></td></tr></tbody></table><p>安装任意角色后重启 opencode 即可使用。浏览完整角色列表 → <a href="https://github.com/EricMoin/oh-my-role" target="_blank" rel="noreferrer">oh-my-role 注册表</a></p><hr><h2 id="✨-推荐功能-emperor-—-你的-ai-工程主管" tabindex="-1">✨ 推荐功能：Emperor — 你的 AI 工程主管 <a class="header-anchor" href="#✨-推荐功能-emperor-—-你的-ai-工程主管" aria-label="Permalink to &quot;✨ 推荐功能：Emperor — 你的 AI 工程主管&quot;">​</a></h2><p><a href="https://github.com/EricMoin/oh-my-role" target="_blank" rel="noreferrer">Emperor</a> 是一个顶层编排器，负责计划、委派和验证跨多个专家子代理的复杂工作 — 它自己不写一行代码。</p><h3 id="工作方式" tabindex="-1">工作方式： <a class="header-anchor" href="#工作方式" aria-label="Permalink to &quot;工作方式：&quot;">​</a></h3><ol><li>你用自然语言描述需求</li><li>Emperor <strong>计划</strong>工作（三阶段：草案 → 评审 → 定稿）</li><li><strong>调度</strong>子任务给专业部门（<code>ui</code>、<code>backend</code>、<code>test</code>、<code>data</code>、<code>docs</code>、<code>quality</code>），尽可能并行</li><li><strong>验证</strong>每个结果 — 闭环校验</li><li>必要时<strong>修订</strong> — 带校正预算的两轮重调度</li><li><strong>返回</strong>结构化总结</li></ol><p>了解更多 → <a href="/rolebox-docs/01-Overview/quick-start.html">快速开始</a></p>',35)])])}const b=o(a,[["render",s]]);export{g as __pageData,b as default};
